mapper.select:
SELECT *
from IRRIGATED_PLATFORM_DATA_INFO where (MONITOR_ID,MONITOR_TIME) in (
select MONITOR_ID,max(MONITOR_TIME)
FROM IRRIGATED_PLATFORM_DATA_INFO


        and MONITOR_ID in

            #{item}


    and RECORD_TIME = #{time}

group by MONITOR_ID)

SELECT MONITOR_ID,MONITOR_NAME,YQ_RAIN_FALL_ONE,YQ_RAIN_FALL_THREE,YQ_RAIN_FALL_SIX,YQ_RAIN_FALL_TWELVE,YQ_RAIN_FALL_TWENTY_FOUR FROM IRRIGATED_PLATFORM_DATA_INFO
and TO_CHAR(MONITOR_TIME,'YYYY-MM-DD hh24') = #{date}
and MONITOR_ID in
#{item}
and to_char(MONITOR_TIME,'mi')=00
order by MONITOR_TIME desc

SELECT MONITOR_ID as ID,MONITOR_NAME as STATION_NAME, YQ_RAIN_FALL_ONE as RAINFALL FROM IRRIGATED_PLATFORM_DATA_INFO
and RECORD_TIME = #{date}
and MONITOR_ID in
#{item}
and to_char(MONITOR_TIME,'mi')=00
order by MONITOR_TIME desc

SELECT MONITOR_NAME as name,SQ_MONITOR_FLOW as value,MONITOR_ID as id
from IRRIGATED_PLATFORM_DATA_INFO where (MONITOR_ID,MONITOR_TIME) in (
select MONITOR_ID,max(MONITOR_TIME)
FROM IRRIGATED_PLATFORM_DATA_INFO


        and MONITOR_ID in

            #{item}


    and RECORD_TIME = #{date}

group by MONITOR_ID)
